(2, 'Rabies', 'Rabies Vaccine', 'Legal', 'Legally required vaccine that protects against fatal rabies infection.', '12-16 weeks old', 'First dose at 12-16 weeks, then annual or 3-year booster', 'Low energy, slight swelling, temporary discomfort', 2, NULL, NULL),
(3, 'Bordetella', 'Bordetella (Kennel Cough)', 'Lifestyle', 'Recommended for dogs that attend daycare, grooming, boarding, or social training classes.', '8 weeks and older', 'Every 6-12 months based on exposure risk', 'Sneezing, mild cough, short-term lethargy', 3, NULL, NULL),
(4, 'Leptospirosis', 'Leptospirosis', 'Risk-Based', 'Protects against bacterial infection that can affect dogs and humans in wet environments.', '12 weeks and older', 'Two initial doses, then yearly booster', 'Mild fever, reduced appetite, temporary soreness', 4, NULL, NULL),
(5, 'Canine Influenza', 'Canine Influenza (Dog Flu)', 'Lifestyle', 'Protects against canine flu strains for dogs in social environments.', '8 weeks and older', 'Two-dose series, then annual booster', 'Sleepiness, injection site swelling, mild fever', 5, NULL, NULL),
(6, 'Lyme disease', 'Lyme Disease Vaccine', 'Risk-Based', 'Recommended in tick-prone areas to reduce the risk of Lyme disease.', '9 weeks and older', 'Two-dose series, then annual booster', 'Fatigue, tenderness, short-lived fever', 6, NULL, NULL),
